// deterministic float -> u64 conversions for explicit V casts
// direct C casts are undefined for out-of-range values
static inline uint64_t _v_f64_to_u64(double x) {
	if (!(x >= 0.0)) {
		return 0;
	}
	if (x >= 18446744073709551616.0) {
		return UINT64_MAX;
	}
	return (uint64_t)x;
}


